async (params, browser) => {
  // Open project page
  await browser.open(`https://app.todoist.com/app/project/${params.project_id}`)

  // Wait for content
  await browser.waitForSelector('.task_list_item, [data-testid="task"], [class*="task_list"]', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const projectName = document.querySelector('h1, [class*="project_name"], [data-testid="project-name"], header [class*="title"]')?.textContent?.trim() || ''; const tasks = Array.from(document.querySelectorAll('.task_list_item, [data-testid="task"]')).slice(0,50).map(el => { const title = el.querySelector('.task_content, [data-testid="task-name"]')?.textContent?.trim()||''; const due = el.querySelector('.date, time, [class*="due"]')?.textContent?.trim()||''; const priority = el.querySelector('[class*="priority"]')?.className?.match(/priority_(\d)/)?.[1]||''; const labels = Array.from(el.querySelectorAll('[class*="label"], .tag')).map(l=>l.textContent.trim()); return { title, due_date: due, priority, labels }; }).filter(t=>t.title); return { project_id: '' + params.project_id + '', project_name: projectName, tasks }`)

  return page_data
}
